 Go 的十億列挑戰：從 1 分 45 秒到 3.4 秒的九種解法 https://github.com/benhoyt/go-1brc Baseline $ time cat measurements.txt &gt;/dev/null 0m1.052s $ time wc measurements.txt 1000000000 1179173106 13795293380 measurements.txt 0m55.710s $ time gawk -b -f 1brc.awk measurements.txt &gt;measurements.out 7m35.567s BEGIN { FS = &#34;;&#34; } { if (counts[$1]++) { mins[$1] = $2 &lt; mins[$1] ? $2 : mins[$1] maxs[$1] = $2 &gt; maxs[$1] ? $2 : maxs[$1] } else { mins[$1] = maxs[$1] = $2 # new entry } sums[$1] += $2 } END { printf &#34;{&#34; n = asorti(mins, sorted) for (i = 1; i &lt;= n; i++) { station = sorted[i] min = mins[station] max = maxs[station] mean = sums[station] / counts[station] printf &#34;%s=%.1f/%.1f/%.1f&#34;, station, min, mean, max if (i &lt; n) { printf &#34;, &#34; } } printf &#34;}
&#34; } Solution 1: simple and idiomatic Go // r1: simple, idiomatic Go using bufio.Scanner and strconv.ParseFloat // // ~1.004s for 10M rows package main import ( &#34;bufio&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; &#34;strconv&#34; &#34;strings&#34; ) func r1(inputPath string, output io.Writer) error { type stats struct { min, max, sum float64 count int64 } f, err := os.Open(inputPath) if err != nil { return err } defer f.Close() stationStats := make(map[string]stats) scanner := bufio.NewScanner(f) for scanner.Scan() { line := scanner.Text() station, tempStr, hasSemi := strings.Cut(line, &#34;;&#34;) if !hasSemi { continue } temp, err := strconv.ParseFloat(tempStr, 64) if err != nil { return err } s, ok := stationStats[station] if !ok { s.min = temp s.max = temp s.sum = temp s.count = 1 } else { s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += temp s.count++ } stationStats[station] = s } stations := make([]string, 0, len(stationStats)) for station := range stationStats { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := stationStats[station] mean := s.sum / float64(s.count) fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, s.min, mean, s.max) } fmt.Fprint(output, &#34;}
&#34;) return nil } Solution 2: map with pointer values // r2: use stats pointer as map value to avoid double hashing // // ~921ms for 10M rows (1.09x as fast as r1) package main import ( &#34;bufio&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; &#34;strconv&#34; &#34;strings&#34; ) func r2(inputPath string, output io.Writer) error { type stats struct { min, max, sum float64 count int64 } f, err := os.Open(inputPath) if err != nil { return err } defer f.Close() stationStats := make(map[string]*stats) scanner := bufio.NewScanner(f) for scanner.Scan() { line := scanner.Text() station, tempStr, hasSemi := strings.Cut(line, &#34;;&#34;) if !hasSemi { continue } temp, err := strconv.ParseFloat(tempStr, 64) if err != nil { return err } s := stationStats[station] if s == nil { stationStats[station] = &amp;stats{ min: temp, max: temp, sum: temp, count: 1, } } else { s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += temp s.count++ } } stations := make([]string, 0, len(stationStats)) for station := range stationStats { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := stationStats[station] mean := s.sum / float64(s.count) fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, s.min, mean, s.max) } fmt.Fprint(output, &#34;}
&#34;) return nil } Solution 3: avoid strconv.ParseFloat // r3: parse temperatures manually instead of using strconv.ParseFloat // // ~517ms for 10M rows (1.94x as fast as r1) package main import ( &#34;bufio&#34; &#34;bytes&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; ) func r3(inputPath string, output io.Writer) error { type stats struct { min, max, sum float64 count int64 } f, err := os.Open(inputPath) if err != nil { return err } defer f.Close() stationStats := make(map[string]*stats) scanner := bufio.NewScanner(f) for scanner.Scan() { line := scanner.Bytes() station, tempBytes, hasSemi := bytes.Cut(line, []byte(&#34;;&#34;)) if !hasSemi { continue } negative := false index := 0 if tempBytes[index] == &#39;-&#39; { index++ negative = true } temp := float64(tempBytes[index] - &#39;0&#39;) index++ if tempBytes[index] != &#39;.&#39; { temp = temp*10 + float64(tempBytes[index]-&#39;0&#39;) index++ } index++ // skip &#39;.&#39; temp += float64(tempBytes[index]-&#39;0&#39;) / 10 if negative { temp = -temp } s := stationStats[string(station)] if s == nil { stationStats[string(station)] = &amp;stats{ min: temp, max: temp, sum: temp, count: 1, } } else { s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += temp s.count++ } } stations := make([]string, 0, len(stationStats)) for station := range stationStats { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := stationStats[station] mean := s.sum / float64(s.count) fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, s.min, mean, s.max) } fmt.Fprint(output, &#34;}
&#34;) return nil } Solution 4: fixed point integers // r4: use fixed point int32s (*10) instead of float64s // // ~491ms for 10M rows (2.04x as fast as r1) package main import ( &#34;bufio&#34; &#34;bytes&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; ) func r4(inputPath string, output io.Writer) error { type stats struct { min, max, count int32 sum int64 } f, err := os.Open(inputPath) if err != nil { return err } defer f.Close() stationStats := make(map[string]*stats) scanner := bufio.NewScanner(f) for scanner.Scan() { line := scanner.Bytes() station, tempBytes, hasSemi := bytes.Cut(line, []byte(&#34;;&#34;)) if !hasSemi { continue } negative := false index := 0 if tempBytes[index] == &#39;-&#39; { index++ negative = true } temp := int32(tempBytes[index] - &#39;0&#39;) index++ if tempBytes[index] != &#39;.&#39; { temp = temp*10 + int32(tempBytes[index]-&#39;0&#39;) index++ } index++ // skip &#39;.&#39; temp = temp*10 + int32(tempBytes[index]-&#39;0&#39;) if negative { temp = -temp } s := stationStats[string(station)] if s == nil { stationStats[string(station)] = &amp;stats{ min: temp, max: temp, sum: int64(temp), count: 1, } } else { s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += int64(temp) s.count++ } } stations := make([]string, 0, len(stationStats)) for station := range stationStats { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := stationStats[station] mean := float64(s.sum) / float64(s.count) / 10 fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, float64(s.min)/10, mean, float64(s.max)/10) } fmt.Fprint(output, &#34;}
&#34;) return nil } Solution 5: avoid bytes.Cut // r5: avoid bytes.Cut // // ~442ms for 10M rows (2.27x as fast as r1) package main import ( &#34;bufio&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; ) func r5(inputPath string, output io.Writer) error { type stats struct { min, max, count int32 sum int64 } f, err := os.Open(inputPath) if err != nil { return err } defer f.Close() stationStats := make(map[string]*stats) scanner := bufio.NewScanner(f) for scanner.Scan() { line := scanner.Bytes() end := len(line) tenths := int32(line[end-1] - &#39;0&#39;) ones := int32(line[end-3] - &#39;0&#39;) // line[end-2] is &#39;.&#39; var temp int32 var semicolon int if line[end-4] == &#39;;&#39; { temp = ones*10 + tenths semicolon = end - 4 } else if line[end-4] == &#39;-&#39; { temp = -(ones*10 + tenths) semicolon = end - 5 } else { tens := int32(line[end-4] - &#39;0&#39;) if line[end-5] == &#39;;&#39; { temp = tens*100 + ones*10 + tenths semicolon = end - 5 } else { // &#39;-&#39; temp = -(tens*100 + ones*10 + tenths) semicolon = end - 6 } } station := line[:semicolon] s := stationStats[string(station)] if s == nil { stationStats[string(station)] = &amp;stats{ min: temp, max: temp, sum: int64(temp), count: 1, } } else { s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += int64(temp) s.count++ } } stations := make([]string, 0, len(stationStats)) for station := range stationStats { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := stationStats[station] mean := float64(s.sum) / float64(s.count) / 10 fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, float64(s.min)/10, mean, float64(s.max)/10) } fmt.Fprint(output, &#34;}
&#34;) return nil } Solution 6: avoid bufio.Scanner // r6: don&#39;t use bufio.Scanner to avoid scanning some bytes twice // // ~399ms for 10M rows (2.52x as fast as r1) package main import ( &#34;bytes&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; ) func r6(inputPath string, output io.Writer) error { type stats struct { min, max, count int32 sum int64 } f, err := os.Open(inputPath) if err != nil { return err } defer f.Close() stationStats := make(map[string]*stats) buf := make([]byte, 1024*1024) readStart := 0 for { n, err := f.Read(buf[readStart:]) if err != nil &amp;&amp; err != io.EOF { return err } if readStart+n == 0 { break } chunk := buf[:readStart+n] newline := bytes.LastIndexByte(chunk, &#39;
&#39;) if newline &lt; 0 { break } remaining := chunk[newline+1:] chunk = chunk[:newline+1] for { station, after, hasSemi := bytes.Cut(chunk, []byte(&#34;;&#34;)) if !hasSemi { break } index := 0 negative := false if after[index] == &#39;-&#39; { negative = true index++ } temp := int32(after[index] - &#39;0&#39;) index++ if after[index] != &#39;.&#39; { temp = temp*10 + int32(after[index]-&#39;0&#39;) index++ } index++ // skip &#39;.&#39; temp = temp*10 + int32(after[index]-&#39;0&#39;) index += 2 // skip last digit and &#39;
&#39; if negative { temp = -temp } chunk = after[index:] s := stationStats[string(station)] if s == nil { stationStats[string(station)] = &amp;stats{ min: temp, max: temp, sum: int64(temp), count: 1, } } else { s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += int64(temp) s.count++ } } readStart = copy(buf, remaining) } stations := make([]string, 0, len(stationStats)) for station := range stationStats { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := stationStats[station] mean := float64(s.sum) / float64(s.count) / 10 fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, float64(s.min)/10, mean, float64(s.max)/10) } fmt.Fprint(output, &#34;}
&#34;) return nil } Solution 7: custom hash table // r7: use custom hash table and hash station name as we look for &#39;;&#39; // // ~234ms for 10M rows (4.29x as fast as r1) package main import ( &#34;bytes&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; ) func r7(inputPath string, output io.Writer) error { type stats struct { min, max, count int32 sum int64 } f, err := os.Open(inputPath) if err != nil { return err } defer f.Close() type item struct { key []byte stat *stats } const numBuckets = 1 &lt;&lt; 17 // number of hash buckets (power of 2) items := make([]item, numBuckets) // hash buckets, linearly probed size := 0 // number of active items in items slice buf := make([]byte, 1024*1024) readStart := 0 for { n, err := f.Read(buf[readStart:]) if err != nil &amp;&amp; err != io.EOF { return err } if readStart+n == 0 { break } chunk := buf[:readStart+n] newline := bytes.LastIndexByte(chunk, &#39;
&#39;) if newline &lt; 0 { break } remaining := chunk[newline+1:] chunk = chunk[:newline+1] for { const ( // FNV-1 64-bit constants from hash/fnv. offset64 = 14695981039346656037 prime64 = 1099511628211 ) var station, after []byte hash := uint64(offset64) i := 0 for ; i &lt; len(chunk); i++ { c := chunk[i] if c == &#39;;&#39; { station = chunk[:i] after = chunk[i+1:] break } hash ^= uint64(c) // FNV-1a is XOR then * hash *= prime64 } if i == len(chunk) { break } index := 0 negative := false if after[index] == &#39;-&#39; { negative = true index++ } temp := int32(after[index] - &#39;0&#39;) index++ if after[index] != &#39;.&#39; { temp = temp*10 + int32(after[index]-&#39;0&#39;) index++ } index++ // skip &#39;.&#39; temp = temp*10 + int32(after[index]-&#39;0&#39;) index += 2 // skip last digit and &#39;
&#39; if negative { temp = -temp } chunk = after[index:] hashIndex := int(hash &amp; uint64(numBuckets-1)) for { if items[hashIndex].key == nil { // Found empty slot, add new item (copying key). key := make([]byte, len(station)) copy(key, station) items[hashIndex] = item{ key: key, stat: &amp;stats{ min: temp, max: temp, sum: int64(temp), count: 1, }, } size++ if size &gt; numBuckets/2 { panic(&#34;too many items in hash table&#34;) } break } if bytes.Equal(items[hashIndex].key, station) { // Found matching slot, add to existing stats. s := items[hashIndex].stat s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += int64(temp) s.count++ break } // Slot already holds another key, try next slot (linear probe). hashIndex++ if hashIndex &gt;= numBuckets { hashIndex = 0 } } } readStart = copy(buf, remaining) } stationItems := make([]item, 0, size) for _, item := range items { if item.key == nil { continue } stationItems = append(stationItems, item) } sort.Slice(stationItems, func(i, j int) bool { return string(stationItems[i].key) &lt; string(stationItems[j].key) }) fmt.Fprint(output, &#34;{&#34;) for i, item := range stationItems { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := item.stat mean := float64(s.sum) / float64(s.count) / 10 fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, item.key, float64(s.min)/10, mean, float64(s.max)/10) } fmt.Fprint(output, &#34;}
&#34;) return nil } Solution 8: process chunks in parallel // r8: add some parallelism (but back to non-optimized r1 version) // // ~213ms for 10M rows (4.71x as fast as r1) package main import ( &#34;bufio&#34; &#34;bytes&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; &#34;strconv&#34; &#34;strings&#34; ) type r8Stats struct { min, max, sum float64 count int64 } func r8(inputPath string, output io.Writer) error { parts, err := splitFile(inputPath, maxGoroutines) if err != nil { return err } resultsCh := make(chan map[string]r8Stats) for _, part := range parts { go r8ProcessPart(inputPath, part.offset, part.size, resultsCh) } totals := make(map[string]r8Stats) for i := 0; i &lt; len(parts); i++ { result := &lt;-resultsCh for station, s := range result { ts, ok := totals[station] if !ok { totals[station] = r8Stats{ min: s.min, max: s.max, sum: s.sum, count: s.count, } continue } ts.min = min(ts.min, s.min) ts.max = max(ts.max, s.max) ts.sum += s.sum ts.count += s.count totals[station] = ts } } stations := make([]string, 0, len(totals)) for station := range totals { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := totals[station] mean := s.sum / float64(s.count) fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, s.min, mean, s.max) } fmt.Fprint(output, &#34;}
&#34;) return nil } func r8ProcessPart(inputPath string, fileOffset, fileSize int64, resultsCh chan map[string]r8Stats) { file, err := os.Open(inputPath) if err != nil { panic(err) } defer file.Close() _, err = file.Seek(fileOffset, io.SeekStart) if err != nil { panic(err) } f := io.LimitedReader{R: file, N: fileSize} stationStats := make(map[string]r8Stats) scanner := bufio.NewScanner(&amp;f) for scanner.Scan() { line := scanner.Text() station, tempStr, hasSemi := strings.Cut(line, &#34;;&#34;) if !hasSemi { continue } temp, err := strconv.ParseFloat(tempStr, 64) if err != nil { panic(err) } s, ok := stationStats[station] if !ok { s.min = temp s.max = temp s.sum = temp s.count = 1 } else { s.min = min(s.min, temp) s.max = max(s.max, temp) s.sum += temp s.count++ } stationStats[station] = s } resultsCh &lt;- stationStats } type part struct { offset, size int64 } func splitFile(inputPath string, numParts int) ([]part, error) { const maxLineLength = 100 f, err := os.Open(inputPath) if err != nil { return nil, err } st, err := f.Stat() if err != nil { return nil, err } size := st.Size() splitSize := size / int64(numParts) buf := make([]byte, maxLineLength) parts := make([]part, 0, numParts) offset := int64(0) for i := 0; i &lt; numParts; i++ { if i == numParts-1 { if offset &lt; size { parts = append(parts, part{offset, size - offset}) } break } seekOffset := max(offset+splitSize-maxLineLength, 0) _, err := f.Seek(seekOffset, io.SeekStart) if err != nil { return nil, err } n, _ := io.ReadFull(f, buf) chunk := buf[:n] newline := bytes.LastIndexByte(chunk, &#39;
&#39;) if newline &lt; 0 { return nil, fmt.Errorf(&#34;newline not found at offset %d&#34;, offset+splitSize-maxLineLength) } remaining := len(chunk) - newline - 1 nextOffset := seekOffset + int64(len(chunk)) - int64(remaining) parts = append(parts, part{offset, nextOffset - offset}) offset = nextOffset } return parts, nil } Solution 9: all optimisations plus parallelisation // r9: all the previous optimizations plus parallel execution // // 43ms for 10M rows (23.3x as fast as r1) package main import ( &#34;bytes&#34; &#34;fmt&#34; &#34;io&#34; &#34;os&#34; &#34;sort&#34; ) type r9Stats struct { min, max, count int32 sum int64 } func r9(inputPath string, output io.Writer) error { parts, err := splitFile(inputPath, maxGoroutines) if err != nil { return err } resultsCh := make(chan map[string]*r9Stats) for _, part := range parts { go r9ProcessPart(inputPath, part.offset, part.size, resultsCh) } totals := make(map[string]*r9Stats) for i := 0; i &lt; len(parts); i++ { result := &lt;-resultsCh for station, s := range result { ts := totals[station] if ts == nil { totals[station] = s continue } ts.min = min(ts.min, s.min) ts.max = max(ts.max, s.max) ts.sum += s.sum ts.count += s.count } } stations := make([]string, 0, len(totals)) for station := range totals { stations = append(stations, station) } sort.Strings(stations) fmt.Fprint(output, &#34;{&#34;) for i, station := range stations { if i &gt; 0 { fmt.Fprint(output, &#34;, &#34;) } s := totals[station] mean := float64(s.sum) / float64(s.count) / 10 fmt.Fprintf(output, &#34;%s=%.1f/%.1f/%.1f&#34;, station, float64(s.min)/10, mean, float64(s.max)/10) } fmt.Fprint(output, &#34;}
&#34;) return nil } func r9ProcessPart(inputPath string, fileOffset, fileSize int64, resultsCh chan map[string]*r9Stats) { file, err := os.Open(inputPath) if err != nil { panic(err) } defer file.Close() _, err = file.Seek(fileOffset, io.SeekStart) if err != nil { panic(err) } f := io.LimitedReader{R: file, N: fileSize} type item struct { key []byte stat *r9Stats } const numBuckets = 1 &lt;&lt; 17 // number of hash buckets (power of 2) items := make([]item, numBuckets) // hash buckets, linearly probed size := 0 // number of active items in items slice buf := make([]byte, 1024*1024) readStart := 0 for { n, err := f.Read(buf[readStart:]) if err != nil &amp;&amp; err != io.EOF { panic(err) } if readStart+n == 0 { break } chunk := buf[:readStart+n] newline := bytes.LastIndexByte(chunk, &#39;
