int64(len(data)) } idData := data[:i] i++ // now i points to temperature var temp int64 // parseNumber { negative := data[i] == &#39;-&#39; if negative { i++ } temp = int64(data[i]-&#39;0&#39;) i++ if data[i] != &#39;.&#39; { temp = temp*10 + int64(data[i]-&#39;0&#39;) i++ } i++ // data[i] is &#39;.&#39; temp = temp*10 + int64(data[i]-&#39;0&#39;) if negative { temp = -temp } data = data[i+2:] } // get measurement { i := idHash &amp; uint64(capacity-1) entry := &amp;res.results[i] for { if entry.hash.CompareAndSwap(0, idHash) { // make sure no race occurs as entry may be updated meanwhile as hash has been updated if entry.countT.Add(1) == 1 { entry.nameLen = len(idData) copy(entry.nameBuf[:], idData) entry.minT.Store(temp) entry.maxT.Store(temp) entry.sumT.Store(temp) entry.countT.Add(1) // unlock for update below } else { // wait for countT to be at least 2 for entry init to be complete for entry.countT.Load() &lt; 2 {} // update existing entry minT := entry.minT.Load() for minT &gt; temp { if entry.minT.CompareAndSwap(minT, temp) { break } else { minT = entry.minT.Load() } } maxT := entry.maxT.Load() for maxT &lt; temp { if entry.maxT.CompareAndSwap(maxT, temp) { break } else { maxT = entry.maxT.Load() } } entry.sumT.Add(temp) entry.countT.Add(1) } break } else if entry.hash.Load() == idHash { // the entry is found and may be being updated by another thread // wait for countT to be at least 2 for entry init to be complete for entry.countT.Load() &lt; 2 {} // now that name has been updated, check it is matching if len(idData) == entry.nameLen /* bytes.Compare(idData, entry.nameBuf[0:entry.nameLen]) == 0 */ { // update existing entry minT := entry.minT.Load() for minT &gt; temp { if entry.minT.CompareAndSwap(minT, temp) { break } else { minT = entry.minT.Load() } } maxT := entry.maxT.Load() for maxT &lt; temp { if entry.maxT.CompareAndSwap(maxT, temp) { break } else { maxT = entry.maxT.Load() } } entry.sumT.Add(temp) entry.countT.Add(1) break } else { // name does not match idData so jump to next entry i = (i + delta) &amp; uint64(capacity-1) entry = &amp;res.results[i] } } else { i = (i + delta) &amp; uint64(capacity-1) entry = &amp;res.results[i] } } } total++ } res.total.Add(total) } func (entry *measurement) update(temp int64) { minT := entry.minT.Load() for minT &gt; temp { if entry.minT.CompareAndSwap(minT, temp) { break } else { minT = entry.minT.Load() } } maxT := entry.maxT.Load() for maxT &lt; temp { if entry.maxT.CompareAndSwap(maxT, temp) { break } else { maxT = entry.maxT.Load() } } entry.sumT.Add(temp) entry.countT.Add(1) }

 實戰經驗整理的 25 個 Nginx 技巧
server_tokens off;
ssl_protocols TLSv1.2 TLSv1.3;
停用不需要的 HTTP 方法
location / { limit_except GET HEAD POST { deny all; } } 啟用基於 sysctl 的保護 net.ipv4.conf.all.rp_filter = 1 net.ipv4.tcp_syncookies = 1 防止圖片外連 location /images/ { valid_referers none blocked www.domain.com domain.com; if ($invalid_referer) { return 403; } } add_header X-Content-Type-Options nosniff; add_header X-XSS-Protection &quot;1; mode=block&quot;; add_header Strict-Transport-Security &quot;max-age=31536000; includeSubDomains; preload&quot; always;

 Nginx 使用 split_clients 进行简易 A/B 测试 ngx_http_split_clients_module configure 这里举例，我们想要 20% 的用户跳转到网址 https://example.com/，30% 的用户跳转到网址 https://example.org/，剩下的跳转到网址 https://examle.edu/
split_clients &#34;${remote_addr}AAA&#34; $variant { 20% https://example.com/; 30% https://example.org/; * https://example.edu/; } server { listen 80; listen [::]:80; server_name _; return 302 ${variant}; } 上述例子中，按照访客请求的 IP 地址 加上 AAA 字符串 会使用 MurmurHash2 转换成数字，如果得出的数字在前 20%，那么 $variant 值为 https://example.com/，相应的在中间 30% 区间的值为 https://example.org/，其他的为 https://example.edu/。
指定不同的目录 root /var/www/${variant}; 指定不同的首页 index index-${variant}.html;

 25 秒读取 16GB 文件，Go 怎么做到的？ Reading 16GB File in Seconds, Golang 打开文件后，我们有以下两个选项可以选择：
逐行读取文件，这有助于减少内存紧张，但需要更多的时间。 一次将整个文件读入内存并处理该文件，这将消耗更多内存，但会显著减少时间。 由于文件太大，即 16 GB，因此无法将整个文件加载到内存中。但是第一种选择对我们来说也是不可行的，因为我们希望在几秒钟内处理文件。
但你猜怎么着，还有第三种选择。瞧……相比于将整个文件加载到内存中，在 Go 语言中，我们还可以使用 bufio.NewReader()将文件分块加载。
func main() { s := time.Now() args := os.Args[1:] if len(args) != 6 { // for format LogExtractor.exe -f &#34;From Time&#34; -t &#34;To Time&#34; -i &#34;Log file directory location&#34; fmt.Println(&#34;Please give proper command line arguments&#34;) return } startTimeArg := args[1] finishTimeArg := args[3] fileName := args[5] file, err := os.Open(fileName) if err != nil { fmt.Println(&#34;cannot able to read the file&#34;, err) return } defer file.Close() // close after checking err queryStartTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, startTimeArg) if err != nil { fmt.Println(&#34;Could not able to parse the start time&#34;, startTimeArg) return } queryFinishTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, finishTimeArg) if err != nil { fmt.Println(&#34;Could not able to parse the finish time&#34;, finishTimeArg) return } filestat, err := file.Stat() if err != nil { fmt.Println(&#34;Could not able to get the file stat&#34;) return } fileSize := filestat.Size() offset := fileSize - 1 lastLineSize := 0 for { b := make([]byte, 1) n, err := file.ReadAt(b, offset) if err != nil { fmt.Println(&#34;Error reading file &#34;, err) break } char := string(b[0]) if char == &#34;
&#34; { break } offset-- lastLineSize += n } lastLine := make([]byte, lastLineSize) _, err = file.ReadAt(lastLine, offset+1) if err != nil { fmt.Println(&#34;Could not able to read last line with offset&#34;, offset, &#34;and lastline size&#34;, lastLineSize) return } logSlice := strings.SplitN(string(lastLine), &#34;,&#34;, 2) logCreationTimeString := logSlice[0] lastLogCreationTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, logCreationTimeString) if err != nil { fmt.Println(&#34;can not able to parse time : &#34;, err) } if lastLogCreationTime.After(queryStartTime) &amp;&amp; lastLogCreationTime.Before(queryFinishTime) { Process(file, queryStartTime, queryFinishTime) } fmt.Println(&#34;
Time taken - &#34;, time.Since(s)) } func Process(f *os.File, start time.Time, end time.Time) error { linesPool := sync.Pool{New: func() interface{} { lines := make([]byte, 250*1024) return lines }} stringPool := sync.Pool{New: func() interface{} { lines := &#34;&#34; return lines }} r := bufio.NewReader(f) var wg sync.WaitGroup for { buf := linesPool.Get().([]byte) n, err := r.Read(buf) buf = buf[:n] if n == 0 { if err != nil { fmt.Println(err) break } if err == io.EOF { break } return err } nextUntillNewline, err := r.ReadBytes(&#39;
&#39;) if err != io.EOF { buf = append(buf, nextUntillNewline...) } wg.Add(1) go func() { ProcessChunk(buf, &amp;linesPool, &amp;stringPool, start, end) wg.Done() }() } wg.Wait() return nil } func ProcessChunk(chunk []byte, linesPool *sync.Pool, stringPool *sync.Pool, start time.Time, end time.Time) { var wg2 sync.WaitGroup logs := stringPool.Get().(string) logs = string(chunk) linesPool.Put(chunk) logsSlice := strings.Split(logs, &#34;
&#34;) stringPool.Put(logs) chunkSize := 300 n := len(logsSlice) noOfThread := n / chunkSize if n%chunkSize != 0 { noOfThread++ } for i := 0; i &lt; (noOfThread); i++ { wg2.Add(1) go func(s int, e int) { defer wg2.Done() // to avaoid deadlocks for i := s; i &lt; e; i++ { text := logsSlice[i] if len(text) == 0 { continue } logSlice := strings.SplitN(text, &#34;,&#34;, 2) logCreationTimeString := logSlice[0] logCreationTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, logCreationTimeString) if err != nil { fmt.Printf(&#34;
 Could not able to parse the time :%s for log : %v&#34;, logCreationTimeString, text) return } if logCreationTime.After(start) &amp;&amp; logCreationTime.Before(end) { // fmt.Println(text) } } }(i*chunkSize, int(math.Min(float64((i+1)*chunkSize), float64(len(logsSlice))))) } wg2.Wait() logsSlice = nil }

 自定义路由日志的格式 Gin 运行多个服务 XML、JSON、YAML 和 ProtoBuf 渲染（输出格式） 自定义路由日志的格式 default
[GIN-debug] POST /foo --&gt; main.main.func1 (3 handlers) [GIN-debug] GET /bar --&gt; main.main.func2 (3 handlers) [GIN-debug] GET /status --&gt; main.main.func3 (3 handlers) import ( &#34;log&#34; &#34;net/http&#34; &#34;github.com/gin-gonic/gin&#34; ) func main() { r := gin.Default() gin.DebugPrintRouteFunc = func(httpMethod, absolutePath, handlerName string, nuHandlers int) { log.Printf(&#34;endpoint %v %v %v %v\n&#34;, httpMethod, absolutePath, handlerName, nuHandlers) } r.POST(&#34;/foo&#34;, func(c *gin.Context) { c.JSON(http.StatusOK, &#34;foo&#34;) }) r.GET(&#34;/bar&#34;, func(c *gin.Context) { c.JSON(http.StatusOK, &#34;bar&#34;) }) r.GET(&#34;/status&#34;, func(c *gin.Context) { c.JSON(http.StatusOK, &#34;ok&#34;) }) // Listen and Server in http://0.0.0.0:8080 r.Run() } Gin 运行多个服务 package main import ( &#34;log&#34; &#34;net/http&#34; &#34;time&#34; &#34;github.com/gin-gonic/gin&#34; &#34;golang.org/x/sync/errgroup&#34; ) var ( g errgroup.Group ) func router01() http.Handler { e := gin.New() e.Use(gin.Recovery()) e.GET(&#34;/&#34;, func(c *gin.Context) { c.JSON( http.StatusOK, gin.H{ &#34;code&#34;: http.StatusOK, &#34;error&#34;: &#34;Welcome server 01&#34;, }, ) }) return e } func router02() http.Handler { e := gin.New() e.Use(gin.Recovery()) e.GET(&#34;/&#34;, func(c *gin.Context) { c.JSON( http.StatusOK, gin.H{ &#34;code&#34;: http.StatusOK, &#34;error&#34;: &#34;Welcome server 02&#34;, }, ) }) return e } func main() { server01 := &amp;http.Server{ Addr: &#34;:8080&#34;, Handler: router01(), ReadTimeout: 5 * time.Second, WriteTimeout: 10 * time.Second, } server02 := &amp;http.Server{ Addr: &#34;:8081&#34;, Handler: router02(), ReadTimeout: 5 * time.Second, WriteTimeout: 10 * time.Second, } g.Go(func() error { return server01.ListenAndServe() }) g.Go(func() error { return server02.ListenAndServe() }) if err := g.Wait(); err != nil { log.Fatal(err) } } XML、JSON、YAML 和 ProtoBuf 渲染（输出格式） SecureJSON 使用 SecureJSON 可以防止 json 劫持，如果返回的数据是数组，则会默认在返回值前加上&quot;while(1)&quot;
func main() { r := gin.Default() // 可以自定义返回的json数据前缀 // r.SecureJsonPrefix(&#34;)]}&#39;,\n&#34;) r.GET(&#34;/someJSON&#34;, func(c *gin.Context) { names := []string{&#34;lena&#34;, &#34;austin&#34;, &#34;foo&#34;} // 将会输出: while(1);[&#34;lena&#34;,&#34;austin&#34;,&#34;foo&#34;] c.SecureJSON(http.StatusOK, names) }) // Listen and serve on 0.0.0.0:8080 r.Run(&#34;:8080&#34;) } JSONP 使用 JSONP 可以跨域传输，如果参数中存在回调参数，那么返回的参数将是回调函数的形式
func main() { r := gin.Default() r.GET(&#34;/JSONP&#34;, func(c *gin.Context) { data := map[string]interface{}{ &#34;foo&#34;: &#34;bar&#34;, } // 访问 http://localhost:8080/JSONP?callback=call // 将会输出: call({foo:&#34;bar&#34;}) c.JSONP(http.StatusOK, data) }) // Listen and serve on 0.0.0.0:8080 r.Run(&#34;:8080&#34;) } AsciiJSON 使用 AsciiJSON 将使特殊字符编码
func main() { r := gin.Default() r.GET(&#34;/someJSON&#34;, func(c *gin.Context) { data := map[string]interface{}{ &#34;lang&#34;: &#34;GO语言&#34;, &#34;tag&#34;: &#34;&lt;br&gt;&#34;, } // 将输出: {&#34;lang&#34;:&#34;GO\u8bed\u8a00&#34;,&#34;tag&#34;:&#34;\u003cbr\u003e&#34;} c.AsciiJSON(http.StatusOK, data) }) // Listen and serve on 0.0.0.0:8080 r.Run(&#34;:8080&#34;) } PureJSON 通常情况下，JSON 会将特殊的 HTML 字符替换为对应的 unicode 字符，比如&lt;替换为\u003c，如果想原样输出 html，则使用 PureJSON，这个特性在Go 1.6及以下版本中无法使用。
func main() { r := gin.Default() // Serves unicode entities r.GET(&#34;/json&#34;, func(c *gin.Context) { c.JSON(200, gin.H{ &#34;html&#34;: &#34;&lt;b&gt;Hello, world!&lt;/b&gt;&#34;, }) }) // Serves literal characters r.GET(&#34;/purejson&#34;, func(c *gin.Context) { c.PureJSON(200, gin.H{ &#34;html&#34;: &#34;&lt;b&gt;Hello, world!&lt;/b&gt;&#34;, }) }) // listen and serve on 0.0.0.0:8080 r.Run(&#34;:8080&#34;) }

 針對特定 Commit Message 觸發 GitHub Actions 現在，只要我推送 wip commit 或任何包含 wip 的 commit，就會在 GitHub Actions 中被標記為跳過。
jobs: format: runs-on: ubuntu-latest if: &#34;! contains(github.event.head_commit.message, &#39;wip&#39;)&#34; 任何包含 [build] 的 commit 會觸發這些工作，其他則會被跳過。
jobs: format: runs-on: ubuntu-latest if: &#34;contains(github.event.head_commit.message, &#39;[build]&#39;)&#34;

 使用 Nginx 和 mod_pagespeed 自動將圖片轉換為 WebP 並輸出 編譯 ngx_pagespeed 首先確保 Nginx 有 --with-compat 編譯參數，這樣就不需要按照一些奇怪的教學讓大家從頭開始編譯 Nginx
incubator: https://github.com/apache/incubator-pagespeed-ngx.git
# 切換到 nginx 原始碼目錄下開始設定編譯環境 ./configure --with-compat --add-dynamic-module=../incubator-pagespeed-ngx # 編譯 modules make modules # 將編譯好的 module 放到 nginx 目錄下 sudo cp objs/ngx_pagespeed.so /etc/nginx/modules/ # 建立快取資料夾以存放自動轉換的圖片 sudo mkdir -p /var/ngx_pagespeed_cache sudo chown -R www-data:www-data /var/ngx_pagespeed_cache load_module modules/ngx_pagespeed.so; # enable pagespeed module on this server block pagespeed on; # Needs to exist and be writable by nginx. Use tmpfs for best performance. pagespeed FileCachePath /var/ngx_pagespeed_cache; # Ensure requests for pagespeed optimized resources go to the pagespeed handler # and no extraneous headers get set. location ~ &#34;\.pagespeed\.([a-z]\.)?[a-z]{2}\.[^.]{10}\.[^.]+&#34; { add_header &#34;&#34; &#34;&#34;; } location ~ &#34;^/pagespeed_static/&#34; { } location ~ &#34;^/ngx_pagespeed_beacon$&#34; { } pagespeed RewriteLevel CoreFilters; 其中最後一段（pagespeed RewriteLevel CoreFilters;）表示啟用的最佳化方式，包含一些基礎的最佳化，例如：
add_head combine_css combine_javascript convert_meta_tags extend_cache fallback_rewrite_css_urls flatten_css_imports inline_css inline_import_to_link inline_javascript rewrite_css rewrite_images rewrite_javascript rewrite_style_attributes_with_url 如果需要加入其他 Filter，可以這樣寫：
pagespeed EnableFilters combine_css,extend_cache,rewrite_images;
所有 Filter 的列表可參考：Configuring PageSpeed Filters。針對圖片轉換，PageSpeed 會自動判斷是否需要轉換；若需要徹底轉成 WebP，還需要加上幾個 filter：
pagespeed EnableFilters convert_png_to_jpeg,convert_jpeg_to_webp;
一些小問題 如果發現圖片沒有自動被轉成 WebP 格式，可以在 URL 後面加上 ?PageSpeedFilters=+debug，然後查看原始碼，並注意圖片後面的內容。在配置過程中遇到的問題如下：
1 &lt;!--4xx status code, preventing rewriting of xxx 由於手上的 Wordpress 機器都放在 Docker 中，前置了 Cloudflare，所以預設的回源方式會出錯。這時需要這樣設定，其中 localhost:2404 是本地 Docker 監聽位址：
pagespeed MapOriginDomain &#34;http://localhost:2404/&#34; &#34;https://nova.moe/&#34;; 2 &lt;!--deadline_exceeded for filter CacheExtender--&gt;&lt;!--deadline_exceeded for filter ImageRewrite--&gt;
這表示 PageSpeed 正在生成對應的快取圖片。
3 &lt;!--The preceding resource was not rewritten because its domain (nova.moe) is not authorized--&gt;
由於有反向代理，SSL 在 Nginx 上就已經結束，需要在代理設定中加入：
proxy_set_header X-Forwarded-Proto $scheme; 並加上：
pagespeed RespectXForwardedProto on;
